export interface RootWord {
  /** emoji icon */ i: string;
  /** the example word */ w: string;
  /** the root letters as they appear in the word */ hl: string;
  /** morphological breakdown, e.g. "bio (life) + -logy (study of)" */ b: string;
  /** kid-facing definition */ d: string;
}
export interface Palette {
  c1: string; c1rgb: string; c2: string; grad: string; pal: [string, string];
}
export interface Tier { n: string; sub: string }
export type TierNum = 1 | 2 | 3 | 4 | 5;
export interface Root {
  /** tier number 1..5 */ t: TierNum;
  /** the root itself, e.g. "Bio" */ root: string;
  /** pronunciation, e.g. "BY-oh" */ say: string;
  /** origin, e.g. "Greek bíos" */ org: string;
  /** core meaning, e.g. "life" */ mean: string;
  /** secondary gloss */ alt: string;
  /** scene key (canvas animation name) */ scene: string;
  /** palette key into PALETTES */ pal: string;
  /** lead sentence (may contain <b> tags) */ lead: string;
  /** exactly three example words */ words: RootWord[];
}

